using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9 manages its own transactions during Migrate(); wrapping in
    // a user transaction now throws. The execution strategy is also unnecessary
    // because Migrate() handles retries internally.
    void ApplyMigrations(AppDbContext db)
    {
        db.Database.Migrate();
    }
}

